import React from "react";
import {ColorPicker, type ColorPickerHSBType, type ColorPickerRGBType} from "primereact/colorpicker";
import type { IKitsInputColorPicker } from "@lmb-it/kitsconcerto-types";
import KitsContainer from "../../helpers/FormContainer";
import { useFormInputController } from "../../helpers/useFormInputController";
import { useComponentDefaults, useResolvedStyle } from "../../../hooks";

/**
 * Web version of KitsInputColorPicker. Uses Primereact's ColorPicker.
 */
const KitsInputColorPicker = ({ ref, ...rawProps }: IKitsInputColorPicker) => {
    const { mergedProps: props, themeStyle, elementStyles } = useComponentDefaults('ColorPicker', rawProps, 'Input');
    const resolvedThemeStyle = useResolvedStyle(themeStyle);
    const resolvedRootStyle = useResolvedStyle(elementStyles?.root || {});

    const {
        id,
        label,
        value,
        defaultValue,
        onChange,
        errors,
        invalid,
        required,
        disabled,
        helperText,
        leftAddon,
        rightAddon,
        colorFormat,
        inline,
        hideError,
        inputSize,
        isFloatedLabel,
        containerStyle,
        attached,
        ...rest
    } = props;

    // Unified controlled/uncontrolled logic
    const { value: displayValue, emitChange } = useFormInputController<string | ColorPickerRGBType | ColorPickerHSBType>({
        value,
        defaultValue,
        onChange,
    });

    const Element = <ColorPicker
        inputRef={ref}
        format={colorFormat}
        inline={inline}
        value={displayValue}
        onChange={(e) => emitChange(e.value!)}
        className="w-full"
        disabled={disabled}
        style={{ borderRadius: 0, ...(resolvedRootStyle || resolvedThemeStyle) }}
    />;

    if (attached) {
        return Element;
    }


    return (
        <KitsContainer
            id={id}
            disabled={disabled}
            required={required}
            helperText={helperText}
            errors={errors}
            invalid={invalid}
            label={label}
            inputSize={inputSize}
            leftAddon={leftAddon}
            rightAddon={rightAddon}
            hideError={hideError}
            isFloatedLabel={isFloatedLabel}
            containerStyle={containerStyle}
            elementStyles={elementStyles}
        >
            {Element}
        </KitsContainer>
    );
};

export default KitsInputColorPicker;
